  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { Link } from 'react-router-dom';
  4	import * as _ from 'lodash';
  5	
  6	import { Timestamp, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
  7	import { getReferenceForModel } from '@openshift-console/dynamic-plugin-sdk/lib/utils/k8s/k8s-ref';
  8	import {
  9	  Alert,
 10	  Card,
 11	  CardBody,
 12	  CardTitle,
 13	  Label,
 14	  Split,
 15	  SplitItem,
 16	  Stack,
 17	  StackItem,
 18	  Tooltip,
 19	} from '@patternfly/react-core';
 20	import { GitAltIcon } from '@patternfly/react-icons';
 21	
 22	import { ConsoleLinkModel } from '../models';
 23	import ExternalLink from '../utils/ExternalLink/ExternalLink';
 24	import { GitOpsEnvironment } from '../utils/gitops-types';
 25	import { K8sResourceKind } from '../utils/types';
 26	
 27	import ArgoCdLink from './ArgoCdLink';
 28	import RenderStatusLabel from './RenderStatusLabel';
 29	import GitOpsResourcesSection from './ResourcesSection';
 30	
 31	import './EnvironmentDetails.scss';
 32	
 33	interface GitOpsDetailsProps {
 34	  envs: GitOpsEnvironment[];
 35	  appName: string;
 36	  manifestURL: string;
 37	  error: Error;
 38	}
 39	
 40	const EnvironmentDetails: React.FC<GitOpsDetailsProps> = ({
 41	  envs,
 42	  appName,
 43	  manifestURL,
 44	  error,
 45	}) => {
 46	  const { t } = useTranslation('plugin__gitops-plugin');
 47	  const [consoleLinks] = useK8sWatchResource<K8sResourceKind[]>({
 48	    isList: true,
 49	    kind: getReferenceForModel(ConsoleLinkModel),
 50	    optional: true,
 51	  });
 52	  const argocdLink = _.find(
 53	    consoleLinks,
 54	    (link: K8sResourceKind) =>
 55	      link.metadata?.name === 'argocd' && link.spec?.location === 'ApplicationMenu',
 56	  );
 57	
 58	  let oldAPI = false;
 59	  if (envs && envs.length > 0) {
 60	    oldAPI = envs[0] && envs[0].deployments ? envs[0].deployments === null : true;
 61	  }
 62	  let errMsg = '';
 63	  if (error != null) {
 64	    errMsg = t('plugin__gitops-plugin~Error cannot retrieve environments');
 65	  }
 66	
 67	  return (
 68	    <div className="gitops-plugin__environment-details">
 69	      {oldAPI && (
 70	        <Alert
 71	          isInline
 72	          title={t('plugin__gitops-plugin~Compatibility Issue')}
 73	          className="gitops-plugin__environment-details__special-message-alert"
 74	        >
 75	          {t('plugin__gitops-plugin~Compatibility Issue Message')}
 76	        </Alert>
 77	      )}
 78	      {error != null && (
 79	        <Alert
 80	          isInline
 81	          title={t('plugin__gitops-plugin~Error Encountered')}
 82	          className="gitops-plugin__environment-details__special-message-alert"
 83	        >
 84	          {errMsg}
 85	        </Alert>
 86	      )}
 87	      {_.map(
 88	        envs,
 89	        (env) =>
 90	          env && (
 91	            <Stack
 92	              className="gitops-plugin__environment-details__env-section"
 93	              key={env.environment}
 94	            >
 95	              <StackItem>
 96	                <Card>
 97	                  <CardTitle className="gitops-plugin__environment-details__env-section__header">
 98	                    <Stack>
 99	                      <StackItem>
100	                        <h2 className="co-section-heading co-truncate co-nowrap gitops-plugin__environment-details__env-section__app-name">
101	                          <Tooltip content={env.environment}>
102	                            <span>{env.environment}</span>
103	                          </Tooltip>
104	                        </h2>
105	                      </StackItem>
106	                      <StackItem className="co-truncate co-nowrap">
107	                        {env.cluster ? (
108	                          <ExternalLink
109	                            additionalClassName="gitops-plugin__environment-details__env-section__cluster-url"
110	                            href={env.cluster}
111	                          >
112	                            {env.cluster}
113	                          </ExternalLink>
114	                        ) : (
115	                          <div className="gitops-plugin__environment-details__env-section__cluster-url-empty-state">
116	                            {t('plugin__gitops-plugin~Cluster URL not available')}
117	                          </div>
118	                        )}
119	                      </StackItem>
120	                      {env.status && (
121	                        <StackItem className="gitops-plugin__environment-details__env-section__status-label">
122	                          <Tooltip content="Sync status">
123	                            <RenderStatusLabel status={env.status} />
124	                          </Tooltip>
125	                        </StackItem>
126	                      )}
127	                    </Stack>
128	                  </CardTitle>
129	                  <CardBody>
130	                    <Stack className="gitops-plugin__environment-details__revision">
131	                      {env.revision ? (
132	                        <>
133	                          {env.revision.message ? (
134	                            <StackItem className="gitops-plugin__environment-details__message">
135	                              {t('plugin__gitops-plugin~{{message}}', {
136	                                message: env.revision.message,
137	                              })}
138	                            </StackItem>
139	                          ) : (
140	                            <StackItem className="gitops-plugin__environment-details__warning-message">
141	                              <span>{t('plugin__gitops-plugin~Commit message not available')}</span>
142	                            </StackItem>
143	                          )}
144	                          <StackItem className="gitops-plugin__environment-details__author-sha">
145	                            {env.revision.author ? (
146	                              <span className="gitops-plugin__environment-details__author">
147	                                {t('plugin__gitops-plugin~by {{author}}', {
148	                                  author: env.revision.author,
149	                                })}{' '}
150	                              </span>
151	                            ) : (
152	                              <span className="gitops-plugin__environment-details__author-unavailable">
153	                                {t('plugin__gitops-plugin~Commit author not available')}{' '}
154	                              </span>
155	                            )}
156	                            {env.revision.revision ? (
157	                              <Label
158	                                className="gitops-plugin__environment-details__sha"
159	                                color="blue"
160	                                icon={<GitAltIcon />}
161	                                variant="outline"
162	                              >
163	                                {env.revision.revision.substring(0, 7)}
164	                              </Label>
165	                            ) : (
166	                              <Label
167	                                className="gitops-plugin__environment-details__sha"
168	                                color="blue"
169	                                icon={<GitAltIcon />}
170	                                variant="outline"
171	                              >
172	                                N/A
173	                              </Label>
174	                            )}
175	                          </StackItem>
176	                        </>
177	                      ) : (
178	                        <span>{t('plugin__gitops-plugin~Commit details not available')}</span>
179	                      )}
180	                      {env.lastDeployed ? (
181	                        <StackItem className="co-truncate co-nowrap gitops-plugin__environment-details__env-section__time">
182	                          {t('plugin__gitops-plugin~Last deployed')}&nbsp;
183	                          <Timestamp timestamp={env.lastDeployed} />
184	                        </StackItem>
185	                      ) : (
186	                        <StackItem className="co-truncate co-nowrap gitops-plugin__environment-details__env-section__time-unavailable">
187	                          <span>{t('plugin__gitops-plugin~Last deployed time not available')}</span>
188	                        </StackItem>
189	                      )}
190	                      <StackItem>
191	                        <Split className="gitops-plugin__environment-details__env-section__deployment-history">
192	                          <SplitItem className="gitops-plugin__environment-details__env-section__deployment-history__deploymentHistoryPageLink">
193	                            <Link
194	                              to={`/envdynamic/${appName}/deploymenthistory?url=${manifestURL}&rowFilter-environment=${env.environment}`}
195	                              title={t('plugin__gitops-plugin~Deployment history')}
196	                            >
197	                              {t<string>('plugin__gitops-plugin~Deployment history')}
198	                            </Link>
199	                          </SplitItem>
200	                          {argocdLink && (
201	                            <Tooltip content="Argo CD">
202	                              <ArgoCdLink
203	                                appName={appName}
204	                                envName={env.environment}
205	                                argocdLink={argocdLink}
206	                              />
207	                            </Tooltip>
208	                          )}
209	                        </Split>
210	                      </StackItem>
211	                    </Stack>
212	                  </CardBody>
213	                </Card>
214	              </StackItem>
215	              <GitOpsResourcesSection
216	                services={env.services}
217	                secrets={env.secrets}
218	                deployments={env.deployments}
219	                routes={env.routes}
220	                roleBindings={env.roleBindings}
221	                clusterRoles={env.clusterRoles}
222	                clusterRoleBindings={env.clusterRoleBindings}
223	              />
224	            </Stack>
225	          ),
226	      )}
227	    </div>
228	  );
229	};
230	
231	export default EnvironmentDetails;

